'use client';

import { useState, useRef } from 'react';
import { Send, Paperclip, Bot } from 'lucide-react';
import ChatMessage from '@/components/ChatMessage';
import QuickReplies from '@/components/QuickReplies';
import DataPanel from '@/components/DataPanel';
import { useSession } from '@/hooks/useSession';
import type { ChatMessage as ChatMessageType } from '@/lib/types';

const WELCOME: ChatMessageType = {
  role: 'ai',
  content:
    'Bienvenue sur TIMEASE ! 👋\n\nJe suis votre assistant pour la création d\'emplois du temps scolaires. Je vais vous guider étape par étape.\n\nPour commencer, parlez-moi de votre école ou importez un fichier Excel.',
  quickReplies: [
    'Configurer mon école',
    'Importer un fichier Excel',
    'Comment ça marche ?',
  ],
};

export default function WorkspacePage() {
  const { schoolData, assignments } = useSession();
  const [messages, setMessages] = useState<ChatMessageType[]>([WELCOME]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    setTimeout(() => messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);
  };

  const handleSend = () => {
    if (!input.trim() || isLoading) return;
    const userMsg: ChatMessageType = { role: 'user', content: input.trim() };
    setMessages((prev) => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    scrollToBottom();

    // Placeholder: chat logic will be wired in Session 3
    setTimeout(() => {
      setMessages((prev) => [
        ...prev,
        {
          role: 'ai',
          content: 'La logique de chat sera connectée dans la prochaine session. Pour le moment, l\'interface est en place ! 🎨',
          quickReplies: ['Configurer mon école', 'Importer un fichier'],
        },
      ]);
      setIsLoading(false);
      scrollToBottom();
    }, 800);
  };

  const handleQuickReply = (reply: string) => {
    setInput(reply);
    // Auto-send
    const userMsg: ChatMessageType = { role: 'user', content: reply };
    setMessages((prev) => [...prev, userMsg]);
    setIsLoading(true);
    scrollToBottom();

    setTimeout(() => {
      setMessages((prev) => [
        ...prev,
        {
          role: 'ai',
          content: `J'ai bien reçu votre message : « ${reply} ». La connexion au backend sera active dans la session 3.`,
          quickReplies: ['D\'accord', 'Continuer'],
        },
      ]);
      setIsLoading(false);
      scrollToBottom();
    }, 800);
  };

  const handleFileClick = () => fileRef.current?.click();

  return (
    <div className="flex h-screen">
      {/* ── Chat panel (60%) ───────────────────────────── */}
      <div className="flex-[3] flex flex-col border-r border-gray-100 dark:border-gray-800">
        {/* Header */}
        <div className="flex items-center gap-3 px-6 py-4 border-b border-gray-100 dark:border-gray-800 bg-white/80 dark:bg-gray-950/80 backdrop-blur-sm">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-teal-500 to-emerald-600 flex items-center justify-center text-white">
            <Bot size={16} />
          </div>
          <div>
            <h2 className="text-sm font-semibold text-gray-800 dark:text-gray-200">
              Assistant TIMEASE
            </h2>
            <p className="text-xs text-gray-400">
              {isLoading ? 'En train de réfléchir…' : 'En ligne'}
            </p>
          </div>
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto px-6 py-4 space-y-4">
          {messages.map((msg, i) => (
            <div key={i}>
              <ChatMessage message={msg} />
              {msg.quickReplies && msg.quickReplies.length > 0 && i === messages.length - 1 && !isLoading && (
                <div className={`${msg.role === 'user' ? 'flex justify-end' : 'ml-11'}`}>
                  <QuickReplies replies={msg.quickReplies} onSelect={handleQuickReply} />
                </div>
              )}
            </div>
          ))}

          {/* Typing indicator */}
          {isLoading && (
            <div className="flex gap-3 animate-in">
              <div className="w-8 h-8 rounded-full bg-gradient-to-br from-teal-500 to-emerald-600 flex items-center justify-center text-white shrink-0">
                <Bot size={14} />
              </div>
              <div className="bg-white dark:bg-gray-900 border border-gray-100 dark:border-gray-800 rounded-2xl rounded-tl-md px-4 py-3 shadow-sm flex gap-1.5 items-center">
                <span className="typing-dot w-2 h-2 rounded-full bg-gray-400" />
                <span className="typing-dot w-2 h-2 rounded-full bg-gray-400" />
                <span className="typing-dot w-2 h-2 rounded-full bg-gray-400" />
              </div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* Input bar */}
        <div className="px-6 py-4 border-t border-gray-100 dark:border-gray-800 bg-white/80 dark:bg-gray-950/80 backdrop-blur-sm">
          <div className="flex items-center gap-2 bg-gray-50 dark:bg-gray-900 rounded-xl px-4 py-2 border border-gray-200 dark:border-gray-800 focus-within:border-teal-400 dark:focus-within:border-teal-600 focus-within:ring-2 focus-within:ring-teal-500/10 transition-all">
            <button
              onClick={handleFileClick}
              className="text-gray-400 hover:text-teal-600 dark:hover:text-teal-400 transition-colors p-1"
              title="Joindre un fichier"
            >
              <Paperclip size={18} />
            </button>
            <input
              ref={fileRef}
              type="file"
              className="hidden"
              accept=".xlsx,.xls,.csv,.pdf,.docx,.txt"
            />
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Décrivez votre école ou posez une question…"
              className="flex-1 bg-transparent outline-none text-sm text-gray-700 dark:text-gray-300 placeholder:text-gray-400 dark:placeholder:text-gray-600"
              disabled={isLoading}
            />
            <button
              onClick={handleSend}
              disabled={!input.trim() || isLoading}
              className="p-2 rounded-lg bg-teal-600 text-white disabled:opacity-30 hover:bg-teal-700 transition-colors"
            >
              <Send size={16} />
            </button>
          </div>
          <p className="text-[11px] text-gray-400 dark:text-gray-600 mt-2 text-center">
            TIMEASE utilise Claude pour analyser vos données scolaires.
          </p>
        </div>
      </div>

      {/* ── Data panel (40%) ──────────────────────────── */}
      <div className="flex-[2] bg-white dark:bg-gray-950 overflow-hidden">
        <DataPanel
          schoolData={schoolData as Record<string, unknown>}
          assignments={assignments as Record<string, unknown>[]}
        />
      </div>
    </div>
  );
}
